import{_ as t,o,c as u,ag as a}from"./chunks/framework.D7Ve6Z7O.js";const i=JSON.parse('{"title":"第一章","description":"","frontmatter":{},"headers":[],"relativePath":"安乐回响-AI/1.md","filePath":"安乐回响-AI/1.md","lastUpdated":1776953967000}'),e={name:"安乐回响-AI/1.md"};function q(r,p,_,s,n,d){return o(),u("div",null,[...p[0]||(p[0]=[a('<h1 id="第一章" tabindex="-1">第一章 <a class="header-anchor" href="#第一章" aria-label="Permalink to &quot;第一章&quot;">​</a></h1><p>雨打在伞面上，密集，急促。</p><p>苏寒从地铁口钻出来时，冷风正好灌进领口。他缩了缩脖子，看见街上的人都在跑——有人抱着公文包顶在头上，有人干脆放弃了，任雨水打湿肩膀。一辆出租车擦着他身边驶过，轮胎碾过积水，泥点溅起来，他侧身躲开，裤脚还是湿了一片。</p><p>他没停，抬头望向前方。</p><p>雨幕里，那栋楼的轮廓模糊又清晰。一格格窗户亮着暖黄的光，像悬在半空的灯笼。私人医院。他今天要去的地方。</p><p>自动门滑开，没有声音。</p><p>苏寒收伞，抖掉伞面的水珠，刚踏进大厅，暖风就扑了过来。眼镜瞬间白了一片。他摘下来，用衣角擦干净，朝前台点了点头，简单的问路后，转身走向电梯。</p><p>电梯门合上。数字跳：1、2、3、4。</p><p>到了。</p><p>他在门口蹭了蹭鞋底的水渍，推开404的门。</p><hr><p>诊室很暗。</p><p>唯一的光来自玻璃墙后面，柔和得像夜灯。一个女人背对着门，正对着玻璃说话，声音很轻，小心翼翼的。</p><p>苏寒没出声。他站在控制台后，看着玻璃另一侧的投影。</p><p>一个老人。</p><p>灰衬衫，花白头发，手里夹着烟。烟雾在投影里慢慢升起，逼真得像真的。</p><p>&quot;爸，你怎么还抽这么多。&quot;女人的声音里有责怪，更多的是无奈。</p><p>老人笑了，声音从扬声器传出来，有点失真，但语气很熟：&quot;医生说了，让我做点想做的事。&quot;</p><p>&quot;我就这么点癖好，在家还得躲厨房抽。现在总算能放松了。&quot;</p><p>他停了停，像想起什么：&quot;你妈呢？她没来？&quot;</p><p>女人笑容僵了一下，勉强扯出个笑：&quot;前两天我还去看了妈，给她扫了墓。&quot;</p><p>苏寒的目光落在控制台上。</p><p>数字在跳：00:09:41。</p><p>九分钟。</p><p>&quot;妈生前最喜欢鲜花。&quot;女人继续说，&quot;我把门前种的波斯菊种子埋她墓前了。明年春天应该能开。&quot;</p><p>老人深吸了口烟，眼神飘向远处，像陷进很久以前的记忆里。烟雾在他脸前散开。</p><p>过了很久，他才回神，看向女人，笑了笑：&quot;是吗……你妈确实喜欢那些。&quot;</p><p>声音忽然低下去：&quot;我也快去找她了。&quot;</p><p>&quot;以后，你要好好照顾自己。&quot;</p><p>女人眼眶红了，但还是点头，继续说着什么。好像只要不停下来，时间就不会走。</p><p>但时间不会停。</p><p>00:05:12。</p><p>00:03:47。</p><p>00:01:20。</p><p>老人的眼神开始涣散。他看着女人，眼里的焦距慢慢消失，像在看一个陌生人。</p><p>&quot;你是……&quot;</p><p>女人愣住了。</p><p>00:00:15。</p><p>老人嘴唇还在动，但发不出声音了。投影开始闪，像信号不好的电视。</p><p>00:00:00。</p><p>画面定格。</p><p>玻璃后的光微微闪了一下，然后彻底暗下去。</p><p>女人还保持着刚才的姿势，盯着空荡荡的玻璃墙，一动不动。</p><hr><p>苏寒站在控制台后，手指悬在删除键上方。</p><p>他按下去。</p><p>屏幕弹出确认框：</p><p>【确认删除数字人格？此操作不可逆。】</p><p>他点了确认。</p><p>进度条开始走。10%、30%、50%……</p><p>苏寒盯着进度条，脑子里浮现出培训时讲师的话：</p><p>&quot;三日期限，写进公共卫生条例的。不可延长，不可回滚。这是这项技术能被允许存在的唯一前提。&quot;</p><p>&quot;为什么是三天？因为旧架构有内存泄漏。数字人格持续运行，会不断占用算力，最终导致逻辑死循环——也就是人格崩溃。&quot;</p><p>&quot;三天，是技术极限。也是对死者最后的尊严。&quot;</p><p>100%。</p><p>【删除完成。】</p><p>苏寒关掉界面，拔下数据线，把设备装回箱子。</p><p>女人还坐在那儿，一动不动。</p><p>苏寒走过去，轻声说：&quot;节哀。&quot;</p><p>女人没反应。</p><p>苏寒没再说什么，转身离开了诊室。</p><hr><p>门在身后无声合上。</p><p>走廊的灯很亮，和诊室里的昏暗形成对比。苏寒走向电梯，按下按钮。</p><p>电梯门开了。</p><p>他走进去，按一楼。</p><p>电梯开始下降。</p><p>苏寒靠在墙上，闭上眼。</p><p>他知道自己做的是对的。</p><p>三天期限，是为了保护那些死去的人。如果让数字人格无限期运行下去，最终只会变成另一种怪物——既不是人，也不是程序，只是一团混乱的数据垃圾。</p><p>关机，是最后的体面。</p><p>但他也知道，这个答案，说服不了刚才那个女人。</p><p>电梯到了一楼。</p><p>门开。</p><p>苏寒走出医院，撑开伞，走进雨里。</p><p>雨还在下，比刚才更大了。</p>',76)])])}const l=t(e,[["render",q]]);export{i as __pageData,l as default};
